`,n.jsx(r.p,{children:"If this sounds like normal backend engineering, that is the point. Agents do not remove backend discipline. They raise the cost of not having it."}),`
`,n.jsx(r.h2,{id:"mcp-servers",children:n.jsx(r.a,{href:"#mcp-servers",children:"MCP servers"})}),`
`,n.jsxs(r.p,{children:["MCP stands for ",n.jsx(r.strong,{children:"Model Context Protocol"}),". The easiest way to think about it:"]}),`
`,n.jsx(r.p,{children:n.jsx(r.strong,{children:"MCP is a standard way for AI applications to connect to external tools and context."})}),`
`,n.jsx(r.p,{children:"Instead of every AI app inventing its own custom integration format, an MCP server exposes capabilities through a shared protocol. An AI client can connect to that server and discover what it provides."}),`
`,n.jsx(r.p,{children:"MCP servers commonly expose three kinds of things:"}),`
`,n.jsxs(r.ul,{children:[`
`,n.jsxs(r.li,{children:[n.jsx(r.strong,{children:"Tools:"})," actions the model can ask to run, such as querying a database or calling an API."]}),`
`,n.jsxs(r.li,{children:[n.jsx(r.strong,{children:"Resources:"})," context the model can read, such as files, documents, database records, or generated reports."]}),`
`,n.jsxs(r.li,{children:[n.jsx(r.strong,{children:"Prompts:"}),' reusable task templates, such as "summarize this incident" or "prepare this code review."']}),`
`]}),`
`,n.jsx(r.p,{children:"The key idea is separation. The agent client handles the conversation and model calls. The MCP server owns access to a specific system."}),`
`,n.jsx(r.p,{children:"For example:"}),`
`,n.jsx(bd,{left:{title:"Agent client",body:"Conversation and model calls"},center:"MCP protocol",right:[{title:"GitHub server",body:"PRs, issues, branches"},{title:"Docs server",body:"Runbooks, specs, internal docs"},{title:"Deploy server",body:"Rollout status and service health"}]}),`
`,n.jsx(r.p,{children:"Each server exposes a clean contract. The agent does not need hardcoded knowledge of every backend API."}),`
`,n.jsx(r.p,{children:"The mistake is treating MCP as magic. MCP does not make tools safe by itself. A dangerous tool exposed through MCP is still dangerous. You still need auth, allow-lists, confirmation flows, logging, rate limits, and output validation."}),`
`,n.jsx(r.p,{children:"MCP is the connector standard. It is not the safety model."}),`
`,n.jsx(r.h2,{id:"streaming-responses",children:n.jsx(r.a,{href:"#streaming-responses",children:"Streaming responses"})}),`
`,n.jsx(r.p,{children:"Streaming means the system sends partial output while the agent is still working."}),`
`,n.jsx(r.p,{children:"For simple chat, streaming looks like text appearing word by word. In agentic systems, streaming is more useful than that. It can show the shape of the work as it happens."}),`
