`,n.jsx(r.li,{children:"The Lambda starts the Test Executor state machine and passes the task token."}),`
`,n.jsx(r.li,{children:"Step Functions pauses without consuming compute."}),`
`,n.jsxs(r.li,{children:["The test executor runs the underlying test infrastructure, writes detailed results to DynamoDB, and calls ",n.jsx(r.code,{children:"SendTaskSuccess"})," or ",n.jsx(r.code,{children:"SendTaskFailure"}),"."]}),`
